import java.nio.ByteBuffer;
import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Using ByteBuffer with dynamically allocated capacity
        ByteBuffer buffer = ByteBuffer.allocate(name.length());

        // Copying the user input into the dynamic buffer
        for (int i = 0; i < name.length(); i++) {
            buffer.put((byte) name.charAt(i));
        }

        System.out.println("Buffer overflow vulnerability fixed successfully!");
    }
}

